import { Link } from "react-router-dom";
import StatusDetails from "../../../utils/StatusDetails";
import StatusDrop from "../../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { epochTogmt } from "../../../utils/Common";
import authService from "src/auth/auth.service";

export const tableJobPositionConstant = (fetchPositionList, handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Position Title",
            cell: (row) => {
                return (
                    <Link to={`/career/position/edit/${row?.id}`}>
                        <span className="sub">{row.title}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
            //width: '300px',
            //grow: 5,
            width: '300px'
        },
        {
            id: 2,
            name: "Department",
            //grow: 2,
            width: '150px',
            selector: (row) => row.department,
        },
        {
            id: 3,
            name: "Created Date",
            //grow: 2.5,
            width: '150px',
            selector: (row) => epochTogmt(row.createTime)
        },
        {
            id: 4,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            //grow: 2.5,
            width: '150px',
            sortable: true,
            reorder: true,
        },
        {
            id: 5,
            name: "Action",
            //grow: 2.5,
            width: '150px',
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.status}
                        type={'CAREERPOSITION'}
                        action={fetchPositionList}
                        key={uuidv4()}
                        publishPermission={"POSITION_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 6,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" } onClick={(e) => { handleConfirmModal(row.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
